module top_module(
    in,
    sel,
    out
);parameter WIDTH = 4;
    parameter SIZE = 4;

    input  [WIDTH*SIZE-1:0] in;
    input        [SIZE-1:0] sel;
    output      [WIDTH-1:0] out;

    genvar i, j;
    generate
        for (i = 0; i < WIDTH; i = i + 1)
        begin : scramble
            wire [SIZE-1:0] din;

            for (j = 0; j < SIZE; j = j + 1)
            begin : in_inf
                wire __din_tmp = in[j*WIDTH + i];
                assign din[j] = __din_tmp;
            end

            assign out[i] = |(din & sel);
        end
    endgenerate
endmodule
